"use strict";parserFactory.register("shitouxs.com",()=>new ShitouxsParser);class ShitouxsParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("#listsss");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("#TextContent")}findChapterTitle(e){return e.querySelector("#mlfy_main_text > h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".bookcover")}extractLanguage(e){return e.querySelector("html").getAttribute("lang")}extractAuthor(e){let t=e.querySelector(".red");return t?.textContent??super.extractAuthor(e)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".bookintromore")]}}